class Solution {
public:
    int largestInteger(int num) {
        vector<int> odd, even;
        while (num > 0) {
            int digit = num % 10;
            if (digit % 2 == 0) even.push_back(digit);
            else odd.push_back(digit);
            num /= 10;
        }
        sort(odd.rbegin(), odd.rend());
        sort(even.rbegin(), even.rend());
        int result = 0;
        int oddIndex = 0, evenIndex = 0;
        while (oddIndex < odd.size() || evenIndex < even.size()) {
            if (oddIndex < odd.size()) result = result * 10 + odd[oddIndex++];
            if (evenIndex < even.size()) result = result * 10 + even[evenIndex++];
            result *= 10;
        }
        return result / 10;
    }
};
